   180→        ...prev,
   181→        `\x1b[31m[Write error: ${error}]\x1b[0m\n`,
   182→      ]);
   183→    }
   184→  }, [processInfo, input, backendMode]);
   185→
   186→  // Handle Enter key in input
   187→  const handleKeyDown = useCallback(
   188→    (event: React.KeyboardEvent) => {
   189→      if (event.key === "Enter") {
   190→        handleSend();
   191→      }
   192→    },
   193→    [handleSend]
   194→  );
   195→
   196→  // Handle token input Enter key
   197→  const handleTokenKeyDown = useCallback(
   198→    (event: React.KeyboardEvent) => {
   199→      if (event.key === "Enter") {
   200→        handleTokenSubmit();
   201→      }
   202→    },
   203→    [handleTokenSubmit]
   204→  );
   205→
   206→  // Parse ANSI codes for display
   207→  const parseAnsi = (text: string): string => {
   208→    return text;
   209→  };
   210→
   211→  const isBackendAvailable = backendMode !== "none";
   212→
   213→  return (
   214→    <Card>
   215→      <CardTitle>
   216→        <Flex>
   217→          <FlexItem>
   218→            <TerminalIcon /> Terminal (PTY)
   219→          </FlexItem>
   220→          <FlexItem>
   221→            <Label
   222→              color={
   223→                backendMode === "tauri"
   224→                  ? "blue"
   225→                  : backendMode === "dev-bridge"
   226→                    ? "teal"
   227→                    : "grey"
   228→              }
   229→            >
   230→              {backendMode === "tauri"
   231→                ? "Native"
   232→                : backendMode === "dev-bridge"
   233→                  ? "Dev Bridge"
   234→                  : "No Backend"}
   235→            </Label>
   236→          </FlexItem>
   237→          <FlexItem>
   238→            <Label
   239→              color={
   240→                status === "running"
   241→                  ? "green"
   242→                  : status === "stopped"
   243→                    ? "red"
   244→                    : "grey"
   245→              }
   246→            >
   247→              {status}
   248→            </Label>
   249→          </FlexItem>
   250→        </Flex>
   251→      </CardTitle>
   252→      <CardBody>
   253→        {/* Warning when no backend available */}
   254→        {backendMode === "none" && !showTokenInput && (
   255→          <Alert
   256→            variant="warning"
   257→            title="No Backend Available"
   258→            isInline
   259→            style={{ marginBottom: "8px" }}
   260→            actionLinks={
   261→              <Button
   262→                variant="link"
   263→                onClick={() => setShowTokenInput(true)}
   264→                style={{ paddingLeft: 0 }}
   265→              >
   266→                <KeyIcon /> Set Dev Bridge Token
   267→              </Button>
   268→            }
   269→          >
   270→            PTY requires the native Tauri app or dev bridge connection. Start
   271→            the app with <code>bun tauri dev</code> and copy the token from the
   272→            terminal.
   273→          </Alert>
   274→        )}
   275→
   276→        {/* Token input */}
   277→        {showTokenInput && (
   278→          <div style={{ marginBottom: "8px" }}>
   279→            <TextInputGroup>
   280→              <TextInputGroupMain
   281→                value={tokenInput}
   282→                onChange={(_e, val) => setTokenInput(val)}
   283→                onKeyDown={handleTokenKeyDown}
   284→                placeholder="Paste dev bridge token from terminal..."
   285→                aria-label="Dev bridge token"
   286→              />
   287→              <TextInputGroupUtilities>
   288→                <Button variant="control" onClick={handleTokenSubmit}>
   289→                  Set
   290→                </Button>
   291→                <Button
   292→                  variant="plain"
   293→                  onClick={() => setShowTokenInput(false)}
   294→                >
   295→                  Cancel
   296→                </Button>
   297→              </TextInputGroupUtilities>
   298→            </TextInputGroup>
   299→          </div>
   300→        )}
   301→
   302→        {/* Dev bridge mode info */}
   303→        {backendMode === "dev-bridge" && (
   304→          <Alert
   305→            variant="info"
   306→            title="Dev Bridge Mode"
   307→            isInline
   308→            style={{ marginBottom: "8px" }}
   309→          >
   310→            Connected via RPC bridge. PTY output is streamed over WebSocket.
   311→          </Alert>
   312→        )}
   313→
   314→        {/* Output area */}
   315→        <div
   316→          ref={outputRef}
   317→          style={{
   318→            height: `${height}px`,
   319→            backgroundColor: "#1e1e1e",
   320→            color: "#d4d4d4",
   321→            fontFamily: "monospace",
   322→            fontSize: "13px",
   323→            padding: "8px",
   324→            overflowY: "auto",
   325→            whiteSpace: "pre-wrap",
   326→            borderRadius: "4px",
   327→            marginBottom: "8px",
   328→          }}
   329→        >
   330→          {output.map((line, i) => (
   331→            <span key={i}>{parseAnsi(line)}</span>
   332→          ))}
   333→          {output.length === 0 && (
   334→            <span style={{ color: "#888" }}>
   335→              {isBackendAvailable
   336→                ? 'Click "Start Shell" to spawn a PTY process...'
   337→                : "No backend available. Start bun tauri dev and set the token."}
   338→            </span>
   339→          )}
   340→        </div>
   341→
   342→        {/* Controls */}
   343→        <Flex>
   344→          {status !== "running" ? (
   345→            <FlexItem>
   346→              <Button
   347→                variant="primary"
   348→                onClick={handleSpawn}
   349→                icon={<PlayIcon />}
   350→                isDisabled={!isBackendAvailable}
   351→              >
   352→                Start Shell
   353→              </Button>
   354→            </FlexItem>
   355→          ) : (
   356→            <>
   357→              <FlexItem grow={{ default: "grow" }}>
   358→                <TextInput
   359→                  value={input}
   360→                  onChange={(_e, val) => setInput(val)}
   361→                  onKeyDown={handleKeyDown}
   362→                  placeholder="Type command and press Enter..."
   363→                  aria-label="Command input"
   364→                />
   365→              </FlexItem>
   366→              <FlexItem>
   367→                <Button variant="secondary" onClick={handleSend}>
   368→                  Send
   369→                </Button>
   370→              </FlexItem>
   371→              <FlexItem>
   372→                <Button
   373→                  variant="danger"
   374→                  onClick={handleKill}
   375→                  icon={<StopIcon />}
   376→                >
   377→                  Kill
   378→                </Button>
   379→              </FlexItem>
