    56→
    57→  const outputRef = useRef<HTMLDivElement>(null);
    58→  const unlistenRef = useRef<UnlistenFn[]>([]);
    59→  const processIdRef = useRef<string | null>(null);
    60→
    61→  // Auto-scroll to bottom when output changes
    62→  useEffect(() => {
    63→    if (outputRef.current) {
    64→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
    65→    }
    66→  }, [output]);
    67→
    68→  // Cleanup listeners on unmount
    69→  useEffect(() => {
    70→    return () => {
    71→      unlistenRef.current.forEach((unlisten) => unlisten());
    72→      unlistenRef.current = [];
    73→    };
    74→  }, []);
    75→
    76→  // Reset state when modal opens with new task
    77→  useEffect(() => {
    78→    if (isOpen && task) {
    79→      setStatus('idle');
