   111→
   112→    setStatus('starting');
   113→    setOutput([]);
   114→    setError(null);
   115→
   116→    try {
   117→      // Spawn Claude Code in the project directory
   118→      const info = await ptySpawn('claude', [], projectPath, 40, 120);
   119→
   120→      setProcessInfo(info);
   121→      processIdRef.current = info.id;
   122→      setStatus('running');
   123→
   124→      setOutput([
   125→        `\x1b[36m╔══════════════════════════════════════════════════════════════╗\x1b[0m\n`,
   126→        `\x1b[36m║  HQ Task Execution                                           ║\x1b[0m\n`,
   127→        `\x1b[36m╚══════════════════════════════════════════════════════════════╝\x1b[0m\n`,
   128→        `\n`,
   129→        `\x1b[33mTask:\x1b[0m ${task.description}\n`,
   130→        `\x1b[33mProject:\x1b[0m ${projectPath}\n`,
   131→        `\n`,
   132→        `\x1b[32m[Starting Claude Code...]\x1b[0m\n`,
   133→        `\n`,
   134→      ]);
   135→
   136→      // Setup event listeners
   137→      const unlistenOutput = await onPtyOutput((payload: PtyOutput) => {
   138→        if (payload.id === info.id) {
   139→          setOutput((prev) => [...prev, payload.data]);
   140→        }
   141→      });
   142→
   143→      const unlistenExit = await onPtyExit((payload: PtyExit) => {
   144→        if (payload.id === info.id) {
   145→          const exitCode = payload.code;
   146→          const success = exitCode === 0;
   147→
   148→          setOutput((prev) => [
   149→            ...prev,
   150→            `\n`,
   151→            success
   152→              ? `\x1b[32m[Task completed successfully (exit code: ${exitCode})]\x1b[0m\n`
   153→              : `\x1b[31m[Task finished with exit code: ${exitCode}]\x1b[0m\n`,
   154→          ]);
   155→
   156→          setStatus(success ? 'success' : 'failed');
   157→          processIdRef.current = null;
   158→
   159→          // Notify parent
   160→          if (task) {
   161→            onComplete(task.id, success);
   162→          }
   163→        }
   164→      });
   165→
   166→      unlistenRef.current = [unlistenOutput, unlistenExit];
