   296→          style={{
   297→            height: '400px',
   298→            backgroundColor: '#1e1e1e',
   299→            color: '#d4d4d4',
   300→            fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace',
   301→            fontSize: '13px',
   302→            padding: '12px',
   303→            overflowY: 'auto',
   304→            whiteSpace: 'pre-wrap',
   305→            borderRadius: '6px',
   306→            marginBottom: '12px',
   307→            border: '1px solid #333',
   308→          }}
   309→        >
   310→          {output.map((line, i) => (
   311→            <span key={i}>{line}</span>
   312→          ))}
   313→          {output.length === 0 && status === 'idle' && (
   314→            <span style={{ color: '#888' }}>
   315→              Click "Start" to begin executing this task with Claude Code...
   316→            </span>
   317→          )}
   318→        </div>
   319→
   320→        {/* Input field (only when running) */}
   321→        {isRunning && (
   322→          <Flex spaceItems={{ default: 'spaceItemsSm' }}>
   323→            <FlexItem grow={{ default: 'grow' }}>
   324→              <TextInput
   325→                value={input}
