   327→                onKeyDown={handleKeyDown}
   328→                placeholder="Type a message to Claude and press Enter..."
   329→                aria-label="Input to Claude"
   330→              />
   331→            </FlexItem>
   332→            <FlexItem>
   333→              <Button variant="secondary" onClick={handleSend} isDisabled={!input.trim()}>
   334→                Send
   335→              </Button>
   336→            </FlexItem>
   337→          </Flex>
   338→        )}
   339→
   340→        {/* Process info */}
   341→        {processInfo && (
