                  </Button>
                  <Button
                    variant="secondary"
                    icon={<FolderOpenIcon />}
                    onClick={handleAddProject}
                  >
                    Open Another Project
                  </Button>
                </div>
              </CardBody>
            </Card>
          </PageSection>

          {/* Progress Card */}
          <PageSection>
            <ProgressCard projectPath={activeProject.path} onRefresh={handleRefreshFeatures} />
          </PageSection>

          {/* Kanban Board */}
