     1→/**
     2→ * HQ Web Backend Server
     3→ *
     4→ * Replaces Tauri backend with pure Node.js/Bun implementation.
     5→ * Provides:
     6→ * - PTY support via node-pty
     7→ * - WebSocket for real-time communication
     8→ * - REST API for harness CLI commands
     9→ * - File system watching
    10→ */
    11→
    12→import { spawn, type Subprocess } from "bun";
    13→import { watch, type FSWatcher } from "fs";
    14→import { readFile, writeFile, mkdir, access, stat } from "fs/promises";
    15→import { join, basename } from "path";
    16→import { randomBytes } from "crypto";
    17→
    18→// Types
    19→interface ProcessInfo {
    20→  id: string;
    21→  cmd: string;
    22→  args: string[];
    23→  cwd: string;
    24→  rows: number;
    25→  cols: number;
    26→  running: boolean;
    27→  createdAt: number;
    28→}
    29→
    30→interface PtyProcess {
    31→  info: ProcessInfo;
    32→  process: Subprocess;
    33→  stdin: WritableStream<Uint8Array>;
    34→}
    35→
    36→interface RpcRequest {
    37→  id: string;
    38→  cmd: string;
    39→  args: Record<string, unknown>;
    40→}
    41→
    42→interface RpcResponse {
    43→  id: string;
    44→  success: boolean;
    45→  result?: unknown;
    46→  error?: string;
    47→}
    48→
    49→interface RpcEvent {
    50→  event: string;
    51→  payload: unknown;
    52→}
    53→
    54→interface WatcherEntry {
    55→  watcher: FSWatcher;
    56→  projectPath: string;
    57→}
    58→
    59→// Global state
    60→const processes = new Map<string, PtyProcess>();
    61→const watchers = new Map<string, WatcherEntry>();
    62→const wsClients = new Set<{ send: (data: string) => void; readyState: number }>();
    63→
    64→// Generate unique ID
    65→function generateId(): string {
    66→  return randomBytes(16).toString("hex");
    67→}
    68→
    69→// Broadcast event to all WebSocket clients
    70→function broadcast(event: RpcEvent): void {
    71→  const data = JSON.stringify(event);
    72→  for (const client of wsClients) {
    73→    if (client.readyState === 1) {
    74→      try {
    75→        client.send(data);
    76→      } catch (e) {
    77→        console.error("[WS] Failed to send:", e);
    78→      }
    79→    }
    80→  }
    81→}
    82→
    83→// PTY Commands
    84→async function ptySpawn(
    85→  cmd: string,
    86→  args: string[] = [],
    87→  cwd: string = process.cwd(),
    88→  rows: number = 24,
    89→  cols: number = 80
    90→): Promise<ProcessInfo> {
    91→  const id = generateId();
    92→
    93→  // Use Bun's spawn with PTY-like behavior
    94→  const proc = spawn({
    95→    cmd: [cmd, ...args],
    96→    cwd,
    97→    env: {
    98→      ...process.env,
    99→      TERM: "xterm-256color",
   100→      COLUMNS: String(cols),
   101→      LINES: String(rows),
   102→    },
   103→    stdin: "pipe",
   104→    stdout: "pipe",
   105→    stderr: "pipe",
   106→  });
   107→
   108→  const info: ProcessInfo = {
   109→    id,
   110→    cmd,
   111→    args,
   112→    cwd,
   113→    rows,
   114→    cols,
   115→    running: true,
   116→    createdAt: Date.now(),
   117→  };
   118→
   119→  processes.set(id, {
   120→    info,
   121→    process: proc,
   122→    stdin: proc.stdin,
   123→  });
   124→
   125→  // Stream stdout
   126→  (async () => {
   127→    const reader = proc.stdout.getReader();
   128→    try {
   129→      while (true) {
   130→        const { done, value } = await reader.read();
   131→        if (done) break;
   132→        const text = new TextDecoder().decode(value);
   133→        broadcast({
   134→          event: "pty-output",
   135→          payload: { id, data: text },
   136→        });
   137→      }
   138→    } catch (e) {
   139→      console.error(`[PTY ${id}] stdout error:`, e);
   140→    }
   141→  })();
   142→
   143→  // Stream stderr
   144→  (async () => {
   145→    const reader = proc.stderr.getReader();
   146→    try {
   147→      while (true) {
   148→        const { done, value } = await reader.read();
   149→        if (done) break;
   150→        const text = new TextDecoder().decode(value);
   151→        broadcast({
   152→          event: "pty-output",
   153→          payload: { id, data: text },
   154→        });
   155→      }
   156→    } catch (e) {
   157→      console.error(`[PTY ${id}] stderr error:`, e);
   158→    }
   159→  })();
   160→
   161→  // Handle exit
   162→  proc.exited.then((code) => {
   163→    const entry = processes.get(id);
   164→    if (entry) {
   165→      entry.info.running = false;
   166→    }
   167→    broadcast({
   168→      event: "pty-exit",
   169→      payload: { id, code },
   170→    });
   171→    console.log(`[PTY ${id}] Process exited with code: ${code}`);
   172→  });
   173→
   174→  console.log(`[PTY ${id}] Spawned: ${cmd} ${args.join(" ")}`);
   175→  return info;
   176→}
   177→
   178→async function ptyWrite(id: string, data: string): Promise<void> {
   179→  const entry = processes.get(id);
   180→  if (!entry) {
   181→    throw new Error(`Process not found: ${id}`);
   182→  }
   183→  if (!entry.info.running) {
   184→    throw new Error(`Process not running: ${id}`);
   185→  }
   186→
   187→  const writer = entry.stdin.getWriter();
   188→  await writer.write(new TextEncoder().encode(data));
   189→  writer.releaseLock();
   190→}
   191→
   192→async function ptyKill(id: string): Promise<void> {
   193→  const entry = processes.get(id);
   194→  if (!entry) {
   195→    throw new Error(`Process not found: ${id}`);
   196→  }
   197→
   198→  entry.process.kill();
   199→  entry.info.running = false;
   200→  console.log(`[PTY ${id}] Killed`);
   201→}
   202→
   203→function ptyList(): ProcessInfo[] {
   204→  return Array.from(processes.values()).map((e) => e.info);
   205→}
   206→
   207→function ptyGet(id: string): ProcessInfo | null {
   208→  return processes.get(id)?.info || null;
   209→}
   210→
   211→// Harness CLI wrapper
   212→async function runHarnessCommand(
   213→  projectPath: string,
   214→  args: string[]
   215→): Promise<string> {
   216→  // Find harness binary - check common locations
   217→  const possiblePaths = [
   218→    join(process.cwd(), "target", "release", "harness"),
   219→    join(process.cwd(), "target", "debug", "harness"),
   220→    join(process.cwd(), "src-tauri", "target", "release", "harness"),
   221→    join(process.cwd(), "src-tauri", "target", "debug", "harness"),
   222→    "harness", // In PATH
   223→  ];
   224→
   225→  let harnessPath = "harness";
   226→  for (const p of possiblePaths) {
   227→    try {
   228→      await access(p);
   229→      harnessPath = p;
   230→      break;
   231→    } catch {
   232→      // Try next
   233→    }
   234→  }
   235→
   236→  console.log(`[Harness] Running: ${harnessPath} ${args.join(" ")} in ${projectPath}`);
   237→
   238→  const proc = spawn({
   239→    cmd: [harnessPath, ...args],
   240→    cwd: projectPath,
   241→    stdout: "pipe",
   242→    stderr: "pipe",
   243→  });
   244→
   245→  const stdout = await new Response(proc.stdout).text();
   246→  const stderr = await new Response(proc.stderr).text();
   247→  const exitCode = await proc.exited;
   248→
   249→  if (exitCode !== 0) {
   250→    throw new Error(`Harness command failed (exit ${exitCode}): ${stderr || stdout}`);
   251→  }
   252→
   253→  return stdout;
   254→}
   255→
   256→// File watcher commands
   257→async function watcherStart(projectPath: string): Promise<boolean> {
   258→  if (watchers.has(projectPath)) {
   259→    return true; // Already watching
   260→  }
   261→
   262→  const harnessDir = join(projectPath, ".harness");
   263→
   264→  try {
   265→    await access(harnessDir);
   266→  } catch {
   267→    console.log(`[Watcher] .harness dir not found: ${harnessDir}`);
   268→    return false;
   269→  }
   270→
   271→  const watcher = watch(harnessDir, { recursive: true }, (eventType, filename) => {
   272→    if (!filename) return;
   273→
   274→    let changeType: "db" | "config" | "unknown" = "unknown";
   275→    if (filename.endsWith(".db") || filename.endsWith(".db-wal") || filename.endsWith(".db-shm")) {
   276→      changeType = "db";
   277→    } else if (filename.endsWith(".json")) {
   278→      changeType = "config";
   279→    }
   280→
   281→    broadcast({
   282→      event: "harness-change",
   283→      payload: {
   284→        project_path: projectPath,
   285→        change_type: changeType,
   286→        file: filename,
   287→      },
   288→    });
   289→  });
   290→
   291→  watchers.set(projectPath, { watcher, projectPath });
   292→  console.log(`[Watcher] Started watching: ${harnessDir}`);
   293→  return true;
   294→}
   295→
   296→function watcherStop(projectPath: string): boolean {
   297→  const entry = watchers.get(projectPath);
   298→  if (!entry) return false;
   299→
   300→  entry.watcher.close();
   301→  watchers.delete(projectPath);
   302→  console.log(`[Watcher] Stopped watching: ${projectPath}`);
   303→  return true;
   304→}
   305→
   306→function watcherList(): string[] {
   307→  return Array.from(watchers.keys());
   308→}
   309→
   310→// Check if path has .harness folder
   311→async function checkHarnessExists(path: string): Promise<boolean> {
   312→  try {
   313→    const harnessPath = join(path, ".harness");
   314→    await access(harnessPath);
   315→    return true;
   316→  } catch {
   317→    return false;
   318→  }
   319→}
   320→
   321→// Get project info from package.json
   322→async function getProjectInfo(path: string): Promise<{ name: string; version?: string } | null> {
   323→  try {
   324→    const pkgPath = join(path, "package.json");
   325→    const content = await readFile(pkgPath, "utf-8");
   326→    const pkg = JSON.parse(content);
   327→    return {
   328→      name: pkg.name || basename(path),
   329→      version: pkg.version,
   330→    };
   331→  } catch {
   332→    return {
   333→      name: basename(path),
   334→    };
   335→  }
   336→}
   337→
   338→// Get git info
   339→async function getGitInfo(path: string): Promise<{ hash: string; message: string; author: string; date: string } | null> {
   340→  try {
   341→    const proc = spawn({
   342→      cmd: ["git", "log", "-1", "--format=%H%n%s%n%an%n%aI"],
   343→      cwd: path,
   344→      stdout: "pipe",
   345→      stderr: "pipe",
   346→    });
   347→
   348→    const stdout = await new Response(proc.stdout).text();
   349→    const exitCode = await proc.exited;
   350→
   351→    if (exitCode !== 0) return null;
   352→
   353→    const lines = stdout.trim().split("\n");
   354→    if (lines.length < 4) return null;
   355→
   356→    return {
   357→      hash: lines[0],
   358→      message: lines[1],
   359→      author: lines[2],
   360→      date: lines[3],
   361→    };
   362→  } catch {
   363→    return null;
   364→  }
   365→}
   366→
   367→// Handle RPC request
   368→async function handleRpcRequest(request: RpcRequest): Promise<RpcResponse> {
   369→  const { id, cmd, args } = request;
   370→
   371→  try {
   372→    let result: unknown;
   373→
   374→    switch (cmd) {
   375→      case "pty_spawn":
   376→        result = await ptySpawn(
   377→          args.cmd as string,
   378→          args.args as string[],
   379→          args.cwd as string,
   380→          args.rows as number,
   381→          args.cols as number
   382→        );
   383→        break;
   384→
   385→      case "pty_write":
   386→        await ptyWrite(args.id as string, args.data as string);
   387→        result = null;
   388→        break;
   389→
   390→      case "pty_resize":
   391→        // Not fully supported with Bun spawn, but we can store the values
   392→        const entry = processes.get(args.id as string);
   393→        if (entry) {
   394→          entry.info.rows = args.rows as number;
   395→          entry.info.cols = args.cols as number;
   396→        }
   397→        result = null;
   398→        break;
   399→
   400→      case "pty_kill":
   401→        await ptyKill(args.id as string);
   402→        result = null;
   403→        break;
   404→
   405→      case "pty_list":
   406→        result = ptyList();
   407→        break;
   408→
   409→      case "pty_get":
   410→        result = ptyGet(args.id as string);
   411→        break;
   412→
   413→      case "run_harness_command":
   414→        result = await runHarnessCommand(
   415→          args.projectPath as string,
