  } catch {
    return false;
  }
}

// Get project info from package.json
async function getProjectInfo(path: string): Promise<{ name: string; version?: string } | null> {
  try {
    const pkgPath = join(path, "package.json");
    const content = await readFile(pkgPath, "utf-8");
    const pkg = JSON.parse(content);
    return {
      name: pkg.name || basename(path),
      version: pkg.version,
    };
  } catch {
    return {
      name: basename(path),
    };
  }
}

// Get git info
async function getGitInfo(path: string): Promise<{ hash: string; message: string; author: string; date: string } | null> {
  try {
    const proc = spawn({
      cmd: ["git", "log", "-1", "--format=%H%n%s%n%an%n%aI"],
      cwd: path,
      stdout: "pipe",
      stderr: "pipe",
    });

    const stdout = await new Response(proc.stdout).text();
    const exitCode = await proc.exited;

    if (exitCode !== 0) return null;

    const lines = stdout.trim().split("\n");
    if (lines.length < 4) return null;

