}

// Handle RPC request
async function handleRpcRequest(request: RpcRequest): Promise<RpcResponse> {
  const { id, cmd, args } = request;

  try {
    let result: unknown;

    switch (cmd) {
      case "pty_spawn":
        result = await ptySpawn(
          args.cmd as string,
          args.args as string[],
          args.cwd as string,
          args.rows as number,
          args.cols as number
        );
