╔══════════════════════════════════════════════════════════════╗
║  HQ Web Backend Server                                       ║
╠══════════════════════════════════════════════════════════════╣
║  Port: ${PORT}                                                 ║
║  WebSocket: ws://localhost:${PORT}/ws                          ║
║  Health: http://localhost:${PORT}/health                       ║
╚══════════════════════════════════════════════════════════════╝
`);

const server = Bun.serve({
  port: PORT,

  async fetch(req, server) {
    const url = new URL(req.url);

    // CORS headers
    const corsHeaders = {
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type",
    };

    // Handle CORS preflight
    if (req.method === "OPTIONS") {
      return new Response(null, { headers: corsHeaders });
    }

    // Health check
    if (url.pathname === "/health") {
      return Response.json(
        { status: "ok", processes: processes.size, watchers: watchers.size },
        { headers: corsHeaders }
      );
    }

    // WebSocket upgrade
    if (url.pathname === "/ws") {
      const upgraded = server.upgrade(req);
      if (!upgraded) {
        return new Response("WebSocket upgrade failed", { status: 400 });
      }
      return undefined;
    }

    // REST API for RPC (alternative to WebSocket)
    if (url.pathname === "/rpc" && req.method === "POST") {
      try {
        const request = await req.json() as RpcRequest;
        const response = await handleRpcRequest(request);
        return Response.json(response, { headers: corsHeaders });
      } catch (e) {
        return Response.json(
          { id: "error", success: false, error: String(e) },
          { status: 400, headers: corsHeaders }
        );
      }
    }

    // Serve static files (if needed for production)
    if (url.pathname === "/" || url.pathname === "/index.html") {
      return new Response("HQ Web Backend Server is running. Connect via WebSocket at /ws", {
        headers: { "Content-Type": "text/plain", ...corsHeaders },
      });
    }

    return new Response("Not found", { status: 404, headers: corsHeaders });
  },

  websocket: {
    open(ws) {
      wsClients.add(ws as any);
      console.log(`[WS] Client connected. Total: ${wsClients.size}`);
    },

    close(ws) {
      wsClients.delete(ws as any);
      console.log(`[WS] Client disconnected. Total: ${wsClients.size}`);
    },

    async message(ws, message) {
      try {
        const request = JSON.parse(message as string) as RpcRequest;
        const response = await handleRpcRequest(request);

        // Send response as RPC event
        ws.send(
          JSON.stringify({
            event: "rpc-response",
            payload: response,
          })
        );
      } catch (e) {
        ws.send(
          JSON.stringify({
            event: "rpc-response",
            payload: {
              id: "error",
              success: false,
              error: String(e),
            },
          })
        );
      }
    },
  },
});

console.log(`Server running at http://localhost:${PORT}`);

// Graceful shutdown
process.on("SIGINT", () => {
  console.log("\n[Server] Shutting down...");

  // Kill all processes
  for (const [id, entry] of processes) {
    try {
      entry.process.kill();
      console.log(`[PTY ${id}] Killed on shutdown`);
    } catch {
      // Ignore
    }
  }

  // Close all watchers
  for (const [path, entry] of watchers) {
    entry.watcher.close();
    console.log(`[Watcher] Stopped: ${path}`);
  }

  process.exit(0);
});

