     1→import { useState, useEffect, useCallback } from 'react';
     2→import {
     3→  Modal,
     4→  ModalBody,
     5→  ModalHeader,
     6→  ModalVariant,
     7→  Button,
     8→  Card,
     9→  CardBody,
    10→  Content,
    11→  EmptyState,
    12→  EmptyStateBody,
    13→  Split,
    14→  SplitItem,
    15→  Stack,
    16→  StackItem,
    17→  Label,
    18→  Alert,
    19→  AlertActionCloseButton,
    20→  Spinner,
    21→  Icon,
    22→  TextInput,
    23→  InputGroup,
    24→  InputGroupItem,
    25→} from '@patternfly/react-core';
    26→import {
    27→  FolderIcon,
    28→  FolderOpenIcon,
    29→  TimesIcon,
    30→} from '@patternfly/react-icons';
    31→import { motion, AnimatePresence } from 'motion/react';
    32→import { checkHarnessExists, runHarnessCommand } from '../lib/rpc';
    33→
    34→// Local storage key for recent projects
    35→const RECENT_PROJECTS_KEY = 'hq_recent_projects';
    36→const MAX_RECENT_PROJECTS = 10;
    37→
    38→export interface RecentProject {
    39→  path: string;
    40→  name: string;
    41→  lastOpened: number;
    42→  isValid?: boolean;
    43→}
    44→
    45→interface ProjectSelectorProps {
    46→  isOpen: boolean;
    47→  onClose: () => void;
    48→  onSelectProject: (path: string, name: string) => void;
    49→}
    50→
    51→// Validate if a folder is a valid harness project (has .harness folder)
    52→async function validateHarnessProject(path: string): Promise<boolean> {
    53→  try {
    54→    const exists = await checkHarnessExists(path);
    55→    return exists;
    56→  } catch {
    57→    // Fallback: assume valid if we can't check
    58→    return true;
    59→  }
    60→}
    61→
    62→// Get project name from path
    63→function getProjectName(path: string): string {
    64→  const parts = path.split(/[/\\]/);
    65→  return parts[parts.length - 1] || 'Unknown Project';
    66→}
    67→
    68→// Load recent projects from localStorage
    69→function loadRecentProjects(): RecentProject[] {
    70→  try {
    71→    const stored = localStorage.getItem(RECENT_PROJECTS_KEY);
    72→    if (stored) {
    73→      return JSON.parse(stored);
    74→    }
    75→  } catch (e) {
    76→    console.error('Failed to load recent projects:', e);
    77→  }
    78→  return [];
    79→}
    80→
    81→// Save recent projects to localStorage
    82→function saveRecentProjects(projects: RecentProject[]): void {
    83→  try {
    84→    localStorage.setItem(RECENT_PROJECTS_KEY, JSON.stringify(projects));
    85→  } catch (e) {
    86→    console.error('Failed to save recent projects:', e);
    87→  }
    88→}
    89→
    90→// Add a project to recent projects
    91→function addToRecentProjects(path: string, name: string): void {
    92→  const projects = loadRecentProjects();
    93→
    94→  // Remove if already exists
    95→  const filtered = projects.filter((p) => p.path !== path);
    96→
    97→  // Add to front
    98→  filtered.unshift({
    99→    path,
   100→    name,
   101→    lastOpened: Date.now(),
   102→    isValid: true,
   103→  });
   104→
   105→  // Keep only MAX_RECENT_PROJECTS
   106→  const trimmed = filtered.slice(0, MAX_RECENT_PROJECTS);
   107→
   108→  saveRecentProjects(trimmed);
   109→}
   110→
   111→// Remove a project from recent projects
   112→function removeFromRecentProjects(path: string): RecentProject[] {
   113→  const projects = loadRecentProjects();
   114→  const filtered = projects.filter((p) => p.path !== path);
   115→  saveRecentProjects(filtered);
   116→  return filtered;
   117→}
   118→
   119→export function ProjectSelector({
   120→  isOpen,
   121→  onClose,
   122→  onSelectProject,
   123→}: ProjectSelectorProps): React.JSX.Element {
   124→  const [recentProjects, setRecentProjects] = useState<RecentProject[]>([]);
   125→  const [isLoading, setIsLoading] = useState(false);
   126→  const [error, setError] = useState<string | null>(null);
   127→  const [validatingProjects, setValidatingProjects] = useState(false);
   128→
   129→  // Path input state (web version - no native file picker)
   130→  const [pathInput, setPathInput] = useState('');
   131→
   132→  // State for "init harness" confirmation
   133→  const [pendingInitPath, setPendingInitPath] = useState<string | null>(null);
   134→  const [isInitializing, setIsInitializing] = useState(false);
   135→
   136→  // Load recent projects on mount
   137→  useEffect(() => {
   138→    if (isOpen) {
   139→      const projects = loadRecentProjects();
   140→      setRecentProjects(projects);
   141→      setError(null);
   142→      setPathInput('');
   143→
   144→      // Validate projects in background
   145→      validateRecentProjects(projects);
   146→    }
   147→  }, [isOpen]);
   148→
   149→  // Validate recent projects in background
   150→  const validateRecentProjects = useCallback(async (projects: RecentProject[]) => {
   151→    if (projects.length === 0) return;
   152→
   153→    setValidatingProjects(true);
   154→
   155→    const validated = await Promise.all(
   156→      projects.map(async (project) => ({
   157→        ...project,
   158→        isValid: await validateHarnessProject(project.path),
   159→      }))
   160→    );
   161→
   162→    setRecentProjects(validated);
   163→    setValidatingProjects(false);
   164→  }, []);
   165→
   166→  // Handle path input submission
   167→  const handlePathSubmit = useCallback(async () => {
   168→    if (!pathInput.trim()) return;
   169→
   170→    const selected = pathInput.trim();
   171→    setIsLoading(true);
   172→    setError(null);
   173→    setPendingInitPath(null);
   174→
   175→    try {
   176→      // Validate it's a harness project
   177→      const isValid = await validateHarnessProject(selected);
   178→
   179→      if (!isValid) {
   180→        // Ask if user wants to initialize harness
   181→        setPendingInitPath(selected);
   182→        setIsLoading(false);
   183→        return;
   184→      }
   185→
   186→      const name = getProjectName(selected);
   187→      addToRecentProjects(selected, name);
   188→      onSelectProject(selected, name);
   189→      onClose();
   190→    } catch (e) {
   191→      console.error('Failed to validate path:', e);
   192→      setError('Failed to validate path. Please check if the path exists.');
   193→    } finally {
   194→      setIsLoading(false);
   195→    }
   196→  }, [pathInput, onSelectProject, onClose]);
   197→
   198→  // Handle Enter key in path input
   199→  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
   200→    if (e.key === 'Enter') {
   201→      handlePathSubmit();
   202→    }
   203→  }, [handlePathSubmit]);
   204→
   205→  // Handle initializing harness in a folder
   206→  const handleInitHarness = useCallback(async () => {
   207→    if (!pendingInitPath) return;
   208→
   209→    setIsInitializing(true);
   210→    setError(null);
   211→
   212→    try {
   213→      // Run harness init command
   214→      await runHarnessCommand(pendingInitPath, ['init']);
   215→
   216→      // Verify it worked
   217→      const isValid = await validateHarnessProject(pendingInitPath);
   218→      if (!isValid) {
   219→        setError('Failed to initialize harness. Please try again.');
   220→        setIsInitializing(false);
   221→        return;
   222→      }
   223→
   224→      const name = getProjectName(pendingInitPath);
   225→      addToRecentProjects(pendingInitPath, name);
   226→      onSelectProject(pendingInitPath, name);
   227→      setPendingInitPath(null);
   228→      onClose();
   229→    } catch (e) {
   230→      console.error('Failed to initialize harness:', e);
   231→      setError(`Failed to initialize harness: ${e}`);
   232→    } finally {
   233→      setIsInitializing(false);
   234→    }
   235→  }, [pendingInitPath, onSelectProject, onClose]);
   236→
   237→  // Cancel pending init
   238→  const handleCancelInit = useCallback(() => {
   239→    setPendingInitPath(null);
   240→  }, []);
   241→
   242→  // Handle select recent project
   243→  const handleSelectRecent = useCallback(async (project: RecentProject) => {
   244→    setError(null);
   245→
   246→    // Re-validate before opening
   247→    const isValid = await validateHarnessProject(project.path);
   248→
   249→    if (!isValid) {
   250→      setError(`Project "${project.name}" no longer contains a valid .harness directory.`);
   251→      return;
   252→    }
   253→
   254→    addToRecentProjects(project.path, project.name);
   255→    onSelectProject(project.path, project.name);
   256→    onClose();
   257→  }, [onSelectProject, onClose]);
   258→
   259→  // Handle remove recent project
   260→  const handleRemoveRecent = useCallback((e: React.MouseEvent, path: string) => {
   261→    e.stopPropagation();
   262→    const updated = removeFromRecentProjects(path);
   263→    setRecentProjects(updated);
   264→  }, []);
   265→
   266→  // Format relative time
   267→  const formatRelativeTime = (timestamp: number): string => {
   268→    const diff = Date.now() - timestamp;
   269→    const minutes = Math.floor(diff / 60000);
   270→    const hours = Math.floor(diff / 3600000);
   271→    const days = Math.floor(diff / 86400000);
   272→
   273→    if (minutes < 1) return 'Just now';
   274→    if (minutes < 60) return `${minutes}m ago`;
   275→    if (hours < 24) return `${hours}h ago`;
   276→    if (days < 7) return `${days}d ago`;
   277→    return new Date(timestamp).toLocaleDateString();
   278→  };
   279→
   280→  return (
   281→    <Modal
   282→      isOpen={isOpen}
   283→      onClose={onClose}
   284→      variant={ModalVariant.medium}
   285→      aria-label="Project Selector"
   286→    >
   287→      <ModalHeader title="Open Project" />
   288→      <ModalBody>
   289→        <Stack hasGutter>
   290→          {/* Error Alert */}
   291→          <AnimatePresence>
   292→            {error && (
   293→              <StackItem>
   294→                <motion.div
   295→                  initial={{ opacity: 0, height: 0 }}
   296→                  animate={{ opacity: 1, height: 'auto' }}
   297→                  exit={{ opacity: 0, height: 0 }}
   298→                >
   299→                  <Alert
   300→                    variant="warning"
   301→                    title="Invalid Project"
   302→                    actionClose={
   303→                      <AlertActionCloseButton onClose={() => setError(null)} />
   304→                    }
   305→                  >
   306→                    {error}
   307→                  </Alert>
   308→                </motion.div>
   309→              </StackItem>
   310→            )}
   311→          </AnimatePresence>
   312→
   313→          {/* Init Harness Confirmation */}
   314→          <AnimatePresence>
   315→            {pendingInitPath && (
   316→              <StackItem>
   317→                <motion.div
   318→                  initial={{ opacity: 0, height: 0 }}
   319→                  animate={{ opacity: 1, height: 'auto' }}
   320→                  exit={{ opacity: 0, height: 0 }}
   321→                >
   322→                  <Alert
   323→                    variant="info"
   324→                    title="Initialize Harness Project?"
   325→                    actionClose={
   326→                      <AlertActionCloseButton onClose={handleCancelInit} />
   327→                    }
   328→                  >
   329→                    <Stack hasGutter>
   330→                      <StackItem>
   331→                        <Content component="p">
   332→                          This folder does not contain a <code>.harness</code> directory.
   333→                          Would you like to initialize it as a Harness project?
   334→                        </Content>
   335→                        <Content component="small" style={{ color: 'var(--pf-t--global--text--color--subtle)' }}>
   336→                          {pendingInitPath}
   337→                        </Content>
   338→                      </StackItem>
   339→                      <StackItem>
   340→                        <Split hasGutter>
   341→                          <SplitItem>
   342→                            <Button
   343→                              variant="primary"
   344→                              onClick={handleInitHarness}
   345→                              isLoading={isInitializing}
   346→                              isDisabled={isInitializing}
   347→                            >
   348→                              {isInitializing ? 'Initializing...' : 'Initialize Harness'}
   349→                            </Button>
   350→                          </SplitItem>
   351→                          <SplitItem>
   352→                            <Button
   353→                              variant="secondary"
   354→                              onClick={handleCancelInit}
   355→                              isDisabled={isInitializing}
   356→                            >
   357→                              Cancel
   358→                            </Button>
   359→                          </SplitItem>
   360→                        </Split>
   361→                      </StackItem>
   362→                    </Stack>
   363→                  </Alert>
   364→                </motion.div>
   365→              </StackItem>
   366→            )}
   367→          </AnimatePresence>
   368→
   369→          {/* Path Input (web version - no native file picker) */}
   370→          <StackItem>
   371→            <Content component="h4" style={{ marginBottom: 8 }}>
   372→              Enter Project Path
   373→            </Content>
   374→            <InputGroup>
   375→              <InputGroupItem isFill>
   376→                <TextInput
   377→                  value={pathInput}
   378→                  onChange={(_e, val) => setPathInput(val)}
   379→                  onKeyDown={handleKeyDown}
   380→                  placeholder="/path/to/your/project"
   381→                  aria-label="Project path"
   382→                  isDisabled={isLoading || isInitializing}
   383→                />
   384→              </InputGroupItem>
   385→              <InputGroupItem>
   386→                <Button
   387→                  variant="primary"
   388→                  icon={<FolderOpenIcon />}
   389→                  onClick={handlePathSubmit}
   390→                  isLoading={isLoading}
   391→                  isDisabled={isLoading || isInitializing || !pathInput.trim()}
   392→                >
   393→                  Open
   394→                </Button>
   395→              </InputGroupItem>
   396→            </InputGroup>
   397→            <Content component="small" style={{ color: 'var(--pf-t--global--text--color--subtle)', marginTop: 4 }}>
   398→              Enter the full path to your project folder and click Open.
   399→            </Content>
   400→          </StackItem>
   401→
   402→          {/* Recent Projects */}
   403→          <StackItem>
   404→            <Content component="h3">
   405→              Recent Projects
   406→              {validatingProjects && (
   407→                <Spinner size="sm" style={{ marginLeft: 8 }} />
   408→              )}
   409→            </Content>
   410→          </StackItem>
   411→
   412→          <StackItem>
   413→            {recentProjects.length === 0 ? (
   414→              <EmptyState
   415→                titleText="No recent projects"
   416→                headingLevel="h4"
   417→                icon={FolderIcon}
   418→              >
   419→                <EmptyStateBody>
   420→                  Enter a project path above to get started. Projects with a .harness
   421→                  directory will be shown here for quick access.
   422→                </EmptyStateBody>
   423→              </EmptyState>
   424→            ) : (
   425→              <Stack hasGutter>
   426→                <AnimatePresence>
   427→                  {recentProjects.map((project, index) => (
   428→                    <StackItem key={project.path}>
   429→                      <motion.div
   430→                        initial={{ opacity: 0, x: -20 }}
   431→                        animate={{ opacity: 1, x: 0 }}
   432→                        exit={{ opacity: 0, x: 20 }}
   433→                        transition={{ delay: index * 0.05 }}
   434→                      >
   435→                        <Card
   436→                          isClickable
   437→                          isSelectable
   438→                          onClick={() => handleSelectRecent(project)}
   439→                          style={{
   440→                            opacity: project.isValid === false ? 0.5 : 1,
   441→                          }}
   442→                        >
   443→                          <CardBody>
   444→                            <Split hasGutter>
   445→                              <SplitItem>
   446→                                <Icon
   447→                                  status={project.isValid === false ? 'warning' : 'info'}
   448→                                  size="lg"
   449→                                >
   450→                                  <FolderIcon />
   451→                                </Icon>
   452→                              </SplitItem>
   453→                              <SplitItem isFilled>
   454→                                <Content>
   455→                                  <Content component="h4" style={{ marginBottom: 4 }}>
   456→                                    {project.name}
   457→                                  </Content>
   458→                                  <Content
   459→                                    component="small"
   460→                                    style={{
   461→                                      color: 'var(--pf-t--global--text--color--subtle)',
   462→                                      wordBreak: 'break-all',
   463→                                    }}
   464→                                  >
   465→                                    {project.path}
   466→                                  </Content>
   467→                                </Content>
   468→                              </SplitItem>
   469→                              <SplitItem>
   470→                                <Split hasGutter>
   471→                                  <SplitItem>
   472→                                    <Label isCompact color="grey">
   473→                                      {formatRelativeTime(project.lastOpened)}
   474→                                    </Label>
   475→                                  </SplitItem>
   476→                                  {project.isValid === false && (
   477→                                    <SplitItem>
   478→                                      <Label isCompact color="orange">
   479→                                        Invalid
   480→                                      </Label>
   481→                                    </SplitItem>
   482→                                  )}
   483→                                  <SplitItem>
   484→                                    <Button
   485→                                      variant="plain"
   486→                                      aria-label="Remove from recent"
   487→                                      onClick={(e) =>
   488→                                        handleRemoveRecent(e, project.path)
   489→                                      }
   490→                                    >
   491→                                      <TimesIcon />
   492→                                    </Button>
   493→                                  </SplitItem>
   494→                                </Split>
   495→                              </SplitItem>
   496→                            </Split>
   497→                          </CardBody>
   498→                        </Card>
   499→                      </motion.div>
   500→                    </StackItem>
